void Solution::stronglyConnectedComponents(vector<vector<int>> &graph, int n) {
  int s = 0, t = 0;
  vector<bool> visited(n, false);
  vector<int> low(n, -1);
  vector<int> disc(n);
  vector<int> stack(n);
  int time = 0;
  vector<vector<int>> res;

  for (int i = 0; i < n; i++) {
    if (!visited[i]) {
      dfs(graph, i, visited, low, disc, stack, time, i, res);
    }
  }

  for (auto& c : res) {
    for (auto& v : c) {
      cout << v << \n";
    }
  }
}
void Solution::dfs(vector<vector<int>> &graph, int u, vector<bool> &visited, vector<int> &low, vector<int> &disc, vector<int> &stack, int time, int p, vector<vector<int>> &res) {
  visited[u] = true;
  low[u] = u;
  disc[u] = time++;
  stack.push_back(u);

  for (int v : graph[u]) {
    if (!visited[v]) {
      dfs(graph, v, visited, low, disc, stack, time, u, res);
    } else if (low[v] >= disc[u]) {
      low[u] = min(low[u], low[v]);
    }
  }

  if (low[u] == u) {
    vector<int> component;
    while (u != p) {
      component.push_back(stack.back());
      stack.pop_back();
      u = stack.back();
    }
    stack.pop_back();
    component.reverse();
    res.push_back(component);
  }
}
